import React, { useState } from 'react';
import axios from 'axios';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';
import { Bar, Doughnut } from 'react-chartjs-2';
import './App.css';
import IndividualAnalysis from './IndividualAnalysis';
import BatchAnalysis from './BatchAnalysis';

ChartJS.register(
  CategoryScale,
  LinearScale,
  BarElement,
  LineElement,
  PointElement,
  ArcElement,
  Title,
  Tooltip,
  Legend
);

const API_BASE = 'http://localhost:5000/api';

function App() {
  const [mode, setMode] = useState('individual');
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState(null);
  const [batchResults, setBatchResults] = useState(null);

  const [customerData, setCustomerData] = useState({
    Tenure: 5.0,
    OrderCount: 5.0,
    CashbackAmount: 12000.0,
    DaySinceLastOrder: 7.0,
    HourSpendOnApp: 30.0,
    OrderAmountHikeFromlastYear: 15.0,
    CouponUsed: 1,
    NumberOfDeviceRegistered: 3,
    Complain: 0,
    SatisfactionScore: 3,
    WarehouseToHome: 10.0,
    NumberOfAddress: 4,
    CityTier: 1,
    PreferredLoginDevice: 'Mobile Phone',
    PreferredPaymentMode: 'Credit Card',
    PreferedOrderCat: 'Laptop & Accessory',
    Gender: 'Male',
    MaritalStatus: 'Married'
  });

  const [batchFile, setBatchFile] = useState(null);

  const handleInputChange = (field, value) => {
    setCustomerData(prev => ({
      ...prev,
      [field]: value
    }));
  };

  const handleIndividualAnalysis = async () => {
    setLoading(true);
    try {
      const response = await axios.post(`${API_BASE}/analyze-single`, {
        customer_data: customerData
      });
      setResults(response.data);
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Error analyzing customer data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  const handleBatchAnalysis = async () => {
    if (!batchFile) {
      alert('Please select a file');
      return;
    }
    setLoading(true);
    const formData = new FormData();
    formData.append('file', batchFile);
    try {
      const response = await axios.post(`${API_BASE}/analyze-batch`, formData, {
        headers: {
          'Content-Type': 'multipart/form-data'
        }
      });
      setBatchResults(response.data);
    } catch (error) {
      console.error('Batch analysis error:', error);
      alert('Error analyzing batch data: ' + (error.response?.data?.error || error.message));
    }
    setLoading(false);
  };

  return (
    <div className="app-container">
      {/* Header */}
      <div className="executive-header">
        <div className="header-content">
          <h1 className="header-title">Executive Churn Intelligence Platform</h1>
          <p className="header-subtitle">Unified predictive insights — action-first, financialized, and presentation-ready</p>
        </div>
      </div>

      {/* Model Status Banner */}
      <div className="model-status-banner">
        <div className="status-content">
          <strong>Model Status</strong>: Using <strong>simulated predictions and feature importances</strong> for demo.
          To enable real predictions:
          1. Install required packages: <code>pip install xgboost catboost</code>
          2. Place 'best_ensemble_churn_model.pkl' and 'feature_names.pkl' into the <code>Artifacts/</code> folder.
        </div>
      </div>

      <div className="main-dashboard">
        {/* Sidebar */}
        <div className="dashboard-sidebar">
          <div className="sidebar-section">
            <div className="sidebar-header">
              <h3>🎯 Analysis Mode</h3>
              <p>Choose your analysis approach</p>
            </div>
            <div className="mode-selection">
              <div
                className={`mode-option ${mode === 'individual' ? 'active' : ''}`}
                onClick={() => setMode('individual')}
              >
                <span className="mode-icon">👤</span>
                <div className="mode-content">
                  <div className="mode-title">Individual Profile Analysis</div>
                </div>
              </div>
              <div
                className={`mode-option ${mode === 'batch' ? 'active' : ''}`}
                onClick={() => setMode('batch')}
              >
                <span className="mode-icon">📊</span>
                <div className="mode-content">
                  <div className="mode-title">Batch File Upload</div>
                </div>
              </div>
            </div>
          </div>
          <div className="sidebar-section">
            <h4>⚡ Quick Actions</h4>
            <button className="quick-action-btn">
              📸 Export Dashboard PDF
            </button>
          </div>
          <div className="sidebar-section">
            <h4>ℹ️ Model Status</h4>
            <div className="status-indicator">
              <div className="status-dot demo"></div>
              <span>Using simulated predictions for demo</span>
            </div>
          </div>
        </div>
        {/* Main Content */}
        <div className="dashboard-content">
          {mode === 'individual' ? (
            <IndividualAnalysis
              customerData={customerData}
              onInputChange={handleInputChange}
              onAnalyze={handleIndividualAnalysis}
              loading={loading}
              results={results}
            />
          ) : (
            <BatchAnalysis
              onFileChange={(e) => setBatchFile(e.target.files[0])}
              onAnalyze={handleBatchAnalysis}
              loading={loading}
              results={batchResults}
            />
          )}
        </div>
      </div>
    </div>
  );
}

export default App;
